<?php
namespace Tests\Feature\Hr;
use App\Models\LegalEntity;use App\Models\User;use App\Modules\Hr\Compensation\Actions\ManageSalaryRecordAction;use App\Modules\Hr\Core\Models\HrLicense;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Organization\Models\HrDepartment;use App\Modules\Hr\Organization\Models\HrPosition;use App\Modules\Hr\Personnel\Models\HrEmployee;use App\Modules\Hr\Personnel\Models\HrEmploymentRecord;use App\Modules\Hr\Workforce\Actions\ManageWorkforcePlanAction;use Illuminate\Support\Facades\DB;use Symfony\Component\HttpKernel\Exception\HttpException;use Tests\TestCase;
class WorkforcePlanningWorkflowTest extends TestCase{use RefreshHrDatabase;public function test_plan_snapshots_fte_and_encrypted_cost_with_second_approval():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$maker=User::factory()->create(['role_id'=>$role]);$approver=User::factory()->create(['role_id'=>$role]);$this->actingAs($maker);$tenant=LegalEntity::create(['user_id'=>$maker->id,'name'=>'Kadro','tax_number'=>'5656565656','is_active'=>true]);app(TenantContext::class)->set($tenant);$department=HrDepartment::create(['legal_entity_id'=>$tenant->id,'name'=>'Üretim','code'=>'URET','is_active'=>true]);$position=HrPosition::create(['legal_entity_id'=>$tenant->id,'department_id'=>$department->id,'title'=>'Uzman','code'=>'UZM','is_active'=>true]);$employee=HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$tenant->id,'employee_number'=>'WF1','national_id_encrypted'=>'enc','national_id_hash'=>'workforce-1','national_id_last_four'=>'0001','first_name'=>'Kadro','last_name'=>'Çalışan','status'=>'active']);HrEmploymentRecord::create(['legal_entity_id'=>$tenant->id,'employee_id'=>$employee->id,'department_id'=>$department->id,'position_id'=>$position->id,'employment_type'=>'full_time','start_date'=>today()->subYear(),'status'=>'active']);$salary=app(ManageSalaryRecordAction::class)->propose($employee,50000,today()->subMonth()->toDateString(),'Kadro maliyeti');$this->actingAs($approver);app(ManageSalaryRecordAction::class)->approve($salary);$this->actingAs($maker);$action=app(ManageWorkforcePlanAction::class);$plan=$action->create(['name'=>'2027 Planı','starts_on'=>'2027-01-01','ends_on'=>'2027-12-31','budget'=>1000000,'currency'=>'TRY']);$action->addLine($plan,$department,$position,2,120000,'Bir açık kadro');$action->submit($plan);try{$action->approve($plan->fresh());$this->fail('Hazırlayan planı onaylayamamalı.');}catch(HttpException $e){$this->assertSame(422,$e->getStatusCode());}$this->actingAs($approver);$approved=$action->approve($plan->fresh());$line=$approved->lines->first();$this->assertSame('approved',$approved->status);$this->assertSame('1.00',$line->actual_fte_snapshot);$this->assertSame(50000.0,$line->actualCost());$rawPlan=DB::table('hr_workforce_plans')->where('id',$plan->id)->value('budget_encrypted');$rawCost=DB::table('hr_workforce_plan_lines')->where('id',$line->id)->value('actual_monthly_cost_encrypted');$this->assertStringNotContainsString('1000000',$rawPlan);$this->assertStringNotContainsString('50000',$rawCost);}}
